import json


def encode_snapshot(tokens, captured_at):
    return json.dumps({"version": 1, "tokens": tokens, "captured_at": captured_at})


def decode_snapshot(payload):
    data = json.loads(payload)
    if data.get("version") != 1:
        raise ValueError("unsupported snapshot")
    return data

