from .snapshot import decode_snapshot, encode_snapshot


class TokenBucket:
    def __init__(self, capacity, refill_per_second, monotonic, wall_clock):
        self.capacity = float(capacity)
        self.refill_per_second = float(refill_per_second)
        self._mono = monotonic
        self._wall = wall_clock
        self.tokens = float(capacity)
        self._last_mono = self._mono()

    def _refill(self):
        now = self._mono()
        elapsed = max(0.0, now - self._last_mono)
        self.tokens = min(self.capacity, self.tokens + elapsed * self.refill_per_second)
        self._last_mono = now

    def consume(self, amount):
        self._refill()
        if amount > self.tokens:
            return False
        self.tokens -= amount
        return True

    def snapshot(self):
        return encode_snapshot(self.tokens, self._mono())

    @classmethod
    def restore(cls, payload, capacity, refill_per_second, monotonic, wall_clock):
        data = decode_snapshot(payload)
        bucket = cls(capacity, refill_per_second, monotonic, wall_clock)
        elapsed = max(0.0, bucket._mono() - float(data["captured_at"]))
        bucket.tokens = min(bucket.capacity, float(data["tokens"]) + elapsed * bucket.refill_per_second)
        bucket._last_mono = bucket._mono()
        return bucket

