from quota.limiter import TokenBucket


def test_live_bucket_refills_with_injected_monotonic_clock():
    now = {"mono": 10.0, "wall": 1000.0}
    bucket = TokenBucket(10, 2, lambda: now["mono"], lambda: now["wall"])
    assert bucket.consume(8)
    now["mono"] = 12.0
    assert bucket.consume(6)
    assert bucket.tokens == 0


def test_restore_inside_same_process_preserves_elapsed_refill():
    old = {"mono": 100.0, "wall": 5000.0}
    bucket = TokenBucket(10, 2, lambda: old["mono"], lambda: old["wall"])
    assert bucket.consume(6)
    payload = bucket.snapshot()
    current = {"mono": 102.0, "wall": 5002.0}
    restored = TokenBucket.restore(payload, 10, 2, lambda: current["mono"], lambda: current["wall"])
    assert restored.tokens == 8
